namespace InventoryApp.Services;

public record EquipmentItem(int Id, string Name, string Location, DateTime LastInspected);

public interface IEquipmentService
{
    Task<List<EquipmentItem>> GetEquipmentAsync();
}

public class EquipmentService : IEquipmentService
{
    public async Task<List<EquipmentItem>> GetEquipmentAsync()
    {
        // Simulate a database call
        await Task.Delay(500);

        return new List<EquipmentItem>
        {
            new(1, "Forklift A", "Warehouse 1", new DateTime(2026, 3, 15)),
            new(2, "Conveyor Belt B", "Warehouse 2", new DateTime(2026, 4, 10)),
            new(3, "Pallet Jack C", "Dock 3", new DateTime(2026, 5, 1)),
            new(4, "Crane D", "Yard", new DateTime(2026, 2, 20)),
            new(5, "Compressor E", "Maintenance Bay", new DateTime(2026, 1, 8)),
            new(6, "Generator F", "Building 4", new DateTime(2025, 12, 12)),
            new(7, "Drill Press G", "Workshop", new DateTime(2026, 4, 28)),
            new(8, "Lathe H", "Workshop", new DateTime(2026, 3, 3)),
        };
    }
}

@page "/inventory"
@using InventoryApp.Services
@inject IEquipmentService EquipmentService
@attribute [StreamRendering]
@rendermode InteractiveServer

<PageTitle>Inventory</PageTitle>

<h1>Equipment Inventory</h1>

@if (items is null)
{
    <p><em>Loading inventory...</em></p>
}
else
{
    <table class="table">
        <thead>
            <tr>
                <th>Id</th>
                <th>Name</th>
                <th>Location</th>
                <th>Last Inspected</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var item in items)
            {
                <tr>
                    <td>@item.Id</td>
                    <td>@item.Name</td>
                    <td>@item.Location</td>
                    <td>@item.LastInspected.ToShortDateString()</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<EquipmentItem>? items;

    protected override async Task OnInitializedAsync()
    {
        items = await EquipmentService.GetEquipmentAsync();
    }
}

